1	//! The `finalize` subcommand: squash + set-bookmark + push a jj
2	//! repo, optionally detached so trailing writes land first.
3	//!
4	//! Built for the bot to atomically finalize its `.claude` session
5	//! repo at end-of-step. Every action is opt-in (`--squash`,
6	//! `--push`, `--detach`, `--delay`). The detached path re-execs
7	//! `vc-x1 finalize --exec …` so its output and errors survive the
8	//! parent exiting; failures are dropped as markers under
9	//! `~/.cache/vc-x1/finalize-status` and surfaced on the next
10	//! `vc-x1` run.
11	
12	use std::path::{Path, PathBuf};
13	use std::process::Stdio;
14	use std::time::{SystemTime, UNIX_EPOCH};
15	
16	use clap::Args;
17	use log::{debug, info};
18	
19	use crate::common::run;
20	use crate::context::Context;
21	
22	/// Directory where the detached finalize child writes failure markers.
23	/// A subsequent `vc-x1` invocation scans this directory and surfaces
24	/// any failures to the user, closing the gap that the detached child's
25	/// non-zero exit isn't observable by the caller.
26	fn status_dir() -> Option<PathBuf> {
27	    std::env::var_os("HOME").map(|h| PathBuf::from(h).join(".cache/vc-x1/finalize-status"))
28	}
29	
30	/// Drop a failure marker for the detached child whose non-zero exit
31	/// the caller can't observe.
32	fn write_failure_marker(params: &FinalizeParams, err: &str) {
33	    let Some(dir) = status_dir() else {
34	        return;
35	    };
36	    if std::fs::create_dir_all(&dir).is_err() {
37	        return;
38	    }
39	    let ns = SystemTime::now()
40	        .duration_since(UNIX_EPOCH)
41	        .map(|d| d.as_nanos())
42	        .unwrap_or(0); // OK: filesystem-sortable timestamp; 0 on the impossible pre-epoch path
43	    let pid = std::process::id();
44	    let path = dir.join(format!("{ns}-{pid}.status"));
45	    let content = format!(
46	        "timestamp_ns={ns}\npid={pid}\nrepo={}\nbookmark={}\nerror={err}\n",
47	        params.repo.display(),
48	        params.bookmark.as_deref().unwrap_or(""),
49	    );
50	    let _ = std::fs::write(&path, content);
51	}
52	
53	/// Read, print, and delete any failure markers left by previous detached
54	/// finalize children. Cheap no-op when the directory doesn't exist.
55	pub fn surface_previous_failures() {
56	    let Some(dir) = status_dir() else {
57	        return;
58	    };
59	    let Ok(entries) = std::fs::read_dir(&dir) else {
60	        return;
61	    };
62	    let mut paths: Vec<PathBuf> = entries
63	        .flatten()
64	        .map(|e| e.path())
65	        .filter(|p| p.extension().and_then(|s| s.to_str()) == Some("status"))
66	        .collect();
67	    paths.sort();
68	    for path in paths {
69	        if let Ok(content) = std::fs::read_to_string(&path) {
70	            eprintln!(
71	                "warn: previous finalize failure ({}):",
72	                path.file_stem()
73	                    .map(|s| s.to_string_lossy())
74	                    .unwrap_or_default() // OK: filename without extension; empty on unexpected absence
75	            );
76	            for line in content.lines() {
77	                eprintln!("  {line}");
78	            }
79	            let _ = std::fs::remove_file(&path);
80	        }
81	    }
82	}
83	
84	/// Squash, set bookmark, and/or push a jj repo.
85	///
86	/// Designed for the bot to atomically finalize its session repo:
87	/// --detach exits immediately, --delay waits for trailing writes,
88	/// --squash folds them in, --bookmark + --push sends it upstream.
89	/// Every flag is opt-in. See README.md for details.
90	#[derive(Args, Debug)]
91	pub struct FinalizeArgs {
92	    /// Path to jj repo
93	    #[arg(long, default_value = ".")]
94	    pub repo: PathBuf,
95	
96	    /// Squash SOURCE into TARGET [default: @,@-]
97	    #[arg(long, value_name = "SOURCE,TARGET", default_missing_value = "@,@-", num_args = 0..=1)]
98	    pub squash: Option<String>,
99	
100	    /// Seconds to wait before squashing
101	    #[arg(long, default_value_t = 10.0)]
102	    pub delay: f64,
103	
104	    /// Existing bookmark to push to remote
105	    #[arg(long, value_name = "BOOKMARK")]
106	    pub push: Option<String>,
107	
108	    /// Detach and run in the background
109	    #[arg(long)]
110	    pub detach: bool,
111	
112	    /// Internal: run exec path (used by detach)
113	    #[arg(long, hide = true)]
114	    pub exec: bool,
115	}
116	
117	/// Parsed squash spec: source and target revisions.
118	#[derive(Debug, Clone)]
119	pub struct SquashSpec {
120	    pub source: String,
121	    pub target: String,
122	}
123	
124	impl SquashSpec {
125	    /// Parse a `SOURCE,TARGET` pair (e.g. `@,@-`); both halves
126	    /// must be non-empty.
127	    fn parse(s: &str) -> Result<Self, String> {
128	        let parts: Vec<&str> = s.split(',').collect();
129	        if parts.len() != 2 || parts[0].is_empty() || parts[1].is_empty() {
130	            return Err(format!(
131	                "invalid --squash value '{s}': expected SOURCE,TARGET (e.g. @,@-)"
132	            ));
133	        }
134	        Ok(SquashSpec {
135	            source: parts[0].to_string(),
136	            target: parts[1].to_string(),
137	        })
138	    }
139	}
140	
141	/// Per-invocation finalize inputs — the clap-free shape the
142	/// `finalize` op works against. Built from `FinalizeArgs` at the
143	/// binary edge via `TryFrom` (fallible: `--squash` parsing and
144	/// repo-path canonicalization). The `--log` path lives on
145	/// `Context`, not here.
146	#[derive(Debug)]
147	pub struct FinalizeParams {
148	    pub repo: PathBuf,
149	    pub squash: Option<SquashSpec>,
150	    pub delay_secs: f64,
151	    pub bookmark: Option<String>,
152	    pub push: bool,
153	    pub detach: bool,
154	    pub exec: bool,
155	}
156	
157	impl TryFrom<&FinalizeArgs> for FinalizeParams {
158	    type Error = String;
159	
160	    /// Parse `--squash`, derive `push`/`bookmark` from `--push`,
161	    /// and canonicalize `--repo` (so the detached child resolves it
162	    /// regardless of cwd).
163	    fn try_from(a: &FinalizeArgs) -> Result<Self, String> {
164	        let squash = a.squash.as_deref().map(SquashSpec::parse).transpose()?;
165	        let repo = std::fs::canonicalize(&a.repo)
166	            .map_err(|e| format!("cannot resolve repo path '{}': {e}", a.repo.display()))?;
167	        Ok(FinalizeParams {
168	            repo,
169	            squash,
170	            delay_secs: a.delay,
171	            bookmark: a.push.clone(),
172	            push: a.push.is_some(),
173	            detach: a.detach,
174	            exec: a.exec,
175	        })
176	    }
177	}
178	
179	/// Validate inputs synchronously before detaching.
180	///
181	/// Catches the common failure modes up front so the parent can exit
182	/// with a visible non-zero status — rather than discovering them in
183	/// the detached child where errors only reach the log file.
184	fn preflight(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
185	    debug!("preflight: checking params");
186	    let repo_str = params.repo.to_string_lossy();
187	    let cwd = std::path::Path::new(".");
188	
189	    // Verify squash revsets resolve to something.
190	    if let Some(ref sq) = params.squash {
191	        jj_rev_exists(&repo_str, cwd, &sq.source)
192	            .map_err(|e| format!("squash source '{}' does not resolve: {e}", sq.source))?;
193	        jj_rev_exists(&repo_str, cwd, &sq.target)
194	            .map_err(|e| format!("squash target '{}' does not resolve: {e}", sq.target))?;
195	    }
196	
197	    // Refuse to operate on a repo with conflicts.
198	    let conflicts = run(
199	        "jj",
200	        &[
201	            "log",
202	            "-r",
203	            "conflicts()",
204	            "--no-graph",
205	            "-T",
206	            "\"x\"",
207	            "-R",
208	            &repo_str,
209	        ],
210	        cwd,
211	    )?;
212	    if !conflicts.is_empty() {
213	        return Err(format!("repo '{repo_str}' has conflicts — resolve before finalize").into());
214	    }
215	
216	    // Bookmark: existence, tracking, forward-only move, push-target description.
217	    if let Some(ref bookmark) = params.bookmark {
218	        let exists = run("jj", &["bookmark", "list", bookmark, "-R", &repo_str], cwd)?;
219	        if exists.is_empty() {
220	            return Err(format!("bookmark '{bookmark}' does not exist").into());
221	        }
222	
223	        crate::common::verify_tracking(&params.repo, bookmark)?;
224	
225	        let target_rev = params
226	            .squash
227	            .as_ref()
228	            .map(|sq| sq.target.as_str())
229	            .unwrap_or("@"); // OK: no squash spec → bookmark will point at current @
230	        let range = run(
231	            "jj",
232	            &[
233	                "log",
234	                "-r",
235	                &format!("{bookmark}::({target_rev})"),
236	                "--no-graph",
237	                "-T",
238	                "\"x\"",
239	                "-R",
240	                &repo_str,
241	            ],
242	            cwd,
243	        )?;
244	        if range.is_empty() {
245	            return Err(format!(
246	                "bookmark '{bookmark}' move is not forward — current position is not an \
247	                 ancestor of '{target_rev}' (would diverge)"
248	            )
249	            .into());
250	        }
251	
252	        if params.push {
253	            let desc = run(
254	                "jj",
255	                &[
256	                    "log",
257	                    "-r",
258	                    target_rev,
259	                    "--no-graph",
260	                    "-T",
261	                    "description",
262	                    "-R",
263	                    &repo_str,
264	                ],
265	                cwd,
266	            )?;
267	            if desc.trim().is_empty() {
268	                return Err(format!(
269	                    "push target '{target_rev}' has no description — push would fail \
270	                     (run `jj describe -r {target_rev} -R {repo_str}` first)"
271	                )
272	                .into());
273	            }
274	        }
275	    }
276	
277	    log_plan(params)?;
278	
279	    Ok(())
280	}
281	
282	/// Return Ok(()) if the revset resolves to one or more commits in `repo`.
283	fn jj_rev_exists(repo: &str, cwd: &std::path::Path, rev: &str) -> Result<(), String> {
284	    run(
285	        "jj",
286	        &["log", "-r", rev, "--no-graph", "-T", "\"x\"", "-R", repo],
287	        cwd,
288	    )
289	    .map_err(|e| e.to_string())?;
290	    Ok(())
291	}
292	
293	/// Log what finalize is about to do so the user sees the plan before detach.
294	fn log_plan(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
295	    let repo_str = params.repo.to_string_lossy();
296	    let cwd = std::path::Path::new(".");
297	
298	    if let Some(ref sq) = params.squash {
299	        info!(
300	            "finalize: squash {} → {} in {}",
301	            sq.source, sq.target, repo_str
302	        );
303	    }
304	    if let Some(ref bookmark) = params.bookmark {
305	        let target_rev = params
306	            .squash
307	            .as_ref()
308	            .map(|sq| sq.target.as_str())
309	            .unwrap_or("@"); // OK: same as above
310	        let current = jj_rev_short(&repo_str, cwd, bookmark).unwrap_or_else(|_| "?".into()); // OK: logging only — fall back to "?" if revset fails
311	        let target = jj_rev_short(&repo_str, cwd, target_rev).unwrap_or_else(|_| "?".into()); // OK: same
312	        info!("finalize: set bookmark '{bookmark}' {current} → {target} ({target_rev})");
313	        if params.push {
314	            info!("finalize: push '{bookmark}' to remote");
315	        }
316	    }
317	
318	    Ok(())
319	}
320	
321	/// Short one-line summary of a revset: `<change_short> <commit_short>`.
322	fn jj_rev_short(repo: &str, cwd: &std::path::Path, rev: &str) -> Result<String, String> {
323	    run(
324	        "jj",
325	        &[
326	            "log",
327	            "-r",
328	            rev,
329	            "--no-graph",
330	            "-T",
331	            "change_id.shortest(8) ++ \" \" ++ commit_id.shortest(8)",
332	            "-R",
333	            repo,
334	        ],
335	        cwd,
336	    )
337	    .map_err(|e| e.to_string())
338	}
339	
340	/// Do the squash / set-bookmark / push work — runs in the detached
341	/// child when `--detach`, inline otherwise.
342	fn finalize_exec(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
343	    debug!("finalize_exec: starting params={params:?}");
344	    let repo_str = params.repo.to_string_lossy();
345	    let cwd = std::path::Path::new(".");
346	
347	    // Squash if requested
348	    if let Some(ref sq) = params.squash {
349	        let delay = std::time::Duration::from_secs_f64(params.delay_secs);
350	        debug!("finalize_exec: sleeping {delay:?}");
351	        std::thread::sleep(delay);
352	
353	        info!("finalize: squashing {} → {}...", sq.source, sq.target);
354	        run(
355	            "jj",
356	            &[
357	                "squash",
358	                "--ignore-immutable",
359	                "--use-destination-message",
360	                "--from",
361	                &sq.source,
362	                "--into",
363	                &sq.target,
364	                "-R",
365	                &repo_str,
366	            ],
367	            cwd,
368	        )?;
369	    }
370	
371	    // Set bookmark and push if requested
372	    if let Some(ref bookmark) = params.bookmark {
373	        // Verify bookmark exists — don't silently create new ones
374	        let result = run("jj", &["bookmark", "list", bookmark, "-R", &repo_str], cwd)?;
375	        if result.is_empty() {
376	            return Err(format!("bookmark '{bookmark}' does not exist").into());
377	        }
378	
379	        let rev = params
380	            .squash
381	            .as_ref()
382	            .map(|sq| sq.target.as_str())
383	            .unwrap_or("@"); // OK: no squash spec → bookmark points at current @
384	        info!("finalize: setting bookmark '{bookmark}' to {rev}...");
385	        run(
386	            "jj",
387	            &["bookmark", "set", bookmark, "-r", rev, "-R", &repo_str],
388	            cwd,
389	        )?;
390	
391	        if params.push {
392	            info!("finalize: pushing '{bookmark}' to origin...");
393	            run(
394	                "jj",
395	                &["git", "push", "--bookmark", bookmark, "-R", &repo_str],
396	                &params.repo,
397	            )?;
398	        }
399	    }
400	
401	    info!("finalize: done");
402	    debug!("finalize_exec: done");
403	    Ok(())
404	}
405	
406	/// Build the argv for the detached re-exec: `finalize --exec …`,
407	/// mirroring `params` plus the `--log` path so the child logs to
408	/// the same file.
409	pub fn build_exec_args(params: &FinalizeParams, log: Option<&Path>) -> Vec<String> {
410	    let mut args = vec![
411	        "finalize".to_string(),
412	        "--exec".to_string(),
413	        "--repo".to_string(),
414	        params.repo.to_string_lossy().to_string(),
415	    ];
416	    if let Some(ref sq) = params.squash {
417	        args.push("--squash".to_string());
418	        args.push(format!("{},{}", sq.source, sq.target));
419	        args.push("--delay".to_string());
420	        args.push(params.delay_secs.to_string());
421	    }
422	    if let Some(ref bookmark) = params.bookmark {
423	        args.push("--push".to_string());
424	        args.push(bookmark.clone());
425	    }
426	    if let Some(log) = log {
427	        args.push("--log".to_string());
428	        args.push(log.to_string_lossy().to_string());
429	    }
430	    args
431	}
432	
433	/// Spawn a detached child process with `--exec` and return immediately.
434	/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
435	/// it to `finalize_exec()` where the actual work happens.
436	fn detach(ctx: &Context, params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
437	    debug!("detach: parent starting params={params:?}");
438	
439	    let exe = std::env::current_exe()?;
440	    let args = build_exec_args(params, ctx.log.as_deref());
441	    debug!("detach: exe={exe:?} args={args:?}");
442	
443	    let mut cmd = std::process::Command::new(exe);
444	    cmd.args(&args).stdin(Stdio::null());
445	
446	    // Hand the child the user's controlling terminal when one exists so
447	    // its output stays visible after the parent exits. Inherited pipes
448	    // are unreliable here — the bash-tool / cron caller typically closes
449	    // its read end on parent exit, silently dropping child writes. Fall
450	    // back to null when there is no tty (pipe-invoked / CI / Windows);
451	    // the log file is authoritative in that case.
452	    match std::fs::OpenOptions::new()
453	        .read(true)
454	        .write(true)
455	        .open("/dev/tty")
456	    {
457	        Ok(tty) => {
458	            debug!("detach: /dev/tty opened, child output → terminal");
459	            let out = tty.try_clone()?;
460	            cmd.stdout(Stdio::from(out));
461	            cmd.stderr(Stdio::from(tty));
462	        }
463	        Err(e) => {
464	            debug!("detach: /dev/tty unavailable ({e}), child output → null");
465	            cmd.stdout(Stdio::null());
466	            cmd.stderr(Stdio::null());
467	        }
468	    }
469	
470	    #[cfg(unix)]
471	    {
472	        use std::os::unix::process::CommandExt;
473	        unsafe {
474	            cmd.pre_exec(|| {
475	                libc::setsid();
476	                Ok(())
477	            });
478	        }
479	    }
480	
481	    let child = cmd.spawn()?;
482	    debug!("detach: spawned child pid={}", child.id());
483	    match &ctx.log {
484	        Some(log) => info!(
485	            "finalize: detached (pid {}), log: {}",
486	            child.id(),
487	            log.display()
488	        ),
489	        None => info!("finalize: detached (pid {})", child.id()),
490	    }
491	    Ok(())
492	}
493	
494	/// Run the `finalize` subcommand: preflight, then either detach a
495	/// child to do the work or do it inline.
496	pub fn finalize(ctx: &Context, params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
497	    // Nothing to do — show help hint
498	    if params.squash.is_none() && !params.push {
499	        return Err("nothing to do (see --help for options)".into());
500	    }
501	
502	    debug!("finalize: entry params={params:?}");
503	
504	    // Validate synchronously before detaching so failures exit with a
505	    // visible non-zero status rather than hiding in the detached child's log.
506	    // Skip in --exec (the re-entered child already passed preflight in the parent).
507	    if !params.exec {
508	        preflight(params)?;
509	    }
510	
511	    let result = if params.detach && !params.exec {
512	        detach(ctx, params)
513	    } else {
514	        finalize_exec(params)
515	    };
516	    match &result {
517	        Ok(()) => debug!("finalize: exit ok"),
518	        Err(e) => {
519	            debug!("finalize: exit err={e}");
520	            // In the detached-child path the caller can't observe our
521	            // non-zero exit. Drop a failure marker so a later vc-x1
522	            // invocation can surface the problem.
523	            if params.exec {
524	                write_failure_marker(params, &e.to_string());
525	            }
526	        }
527	    }
528	    result
529	}
